from typing import List

class Solution:
    def sumDigitDifferences(self, nums: List[int]) -> int:
        # Count frequency of each digit at each position
        digit_counts = [{} for _ in range(len(str(nums[0])))]

        for num in nums:
            num_str = str(num)
            for i, ch in enumerate(num_str):
                digit = ch
                if digit in digit_counts[i]:
                    digit_counts[i][digit] += 1
                else:
                    digit_counts[i][digit] = 1

        # Calculate total digit differences
        total = 0
        n = len(nums)
        for counts in digit_counts:
            for count in counts.values():
                total += count * (n - count)

        return total // 2  # Each pair is counted twice
